appsmith.onReady(() => {
  if (typeof render === 'function') {
    render(appsmith.model || {});
  }
  if (typeof poll === 'function') {
    poll();
  }
});
(function(){
  var tip=document.createElement('div');tip.className='ctip';document.body.appendChild(tip);
  document.body.addEventListener('mouseenter',function(e){
    var el=e.target.closest('[title]');if(!el)return;
    el.dataset.tip=el.getAttribute('title');el.removeAttribute('title');
    tip.textContent=el.dataset.tip;tip.classList.add('show');
  },true);
  document.body.addEventListener('mousemove',function(e){
    if(!tip.classList.contains('show'))return;
    var x=e.clientX+12,y=e.clientY+12;
    if(x+tip.offsetWidth>window.innerWidth)x=e.clientX-tip.offsetWidth-8;
    if(y+tip.offsetHeight>window.innerHeight)y=e.clientY-tip.offsetHeight-8;
    tip.style.left=x+'px';tip.style.top=y+'px';
  },true);
  document.body.addEventListener('mouseleave',function(e){
    var el=e.target;if(!el.dataset||!el.dataset.tip)return;
    el.setAttribute('title',el.dataset.tip);delete el.dataset.tip;
    tip.classList.remove('show');
  },true);
})();

